import SwiftUI
import CloudKit
import Foundation

class CloudKitKeyValueViewModel: ObservableObject {
    @Published var isICloudAvailable = false
    @Published var syncedValue: String = ""
    @Published var errorMessage: String?

    private let store = NSUbiquitousKeyValueStore.default
    private let key = "syncedPreference"

    func checkAccountStatus() {
        CKContainer.default().accountStatus { [weak self] status, error in
            DispatchQueue.main.async {
                guard let self = self else { return }
                if let error = error {
                    self.errorMessage = error.localizedDescription
                    self.isICloudAvailable = false
                    return
                }
                switch status {
                case .available:
                    self.isICloudAvailable = true
                    self.errorMessage = nil
                    self.loadFromStore()
                case .noAccount, .restricted, .couldNotDetermine:
                    self.isICloudAvailable = false
                    self.errorMessage = "iCloud is not available. Sign in to iCloud in Settings to sync."
                @unknown default:
                    self.isICloudAvailable = false
                    self.errorMessage = "iCloud status unknown."
                }
            }
        }
    }

    private func loadFromStore() {
        if let value = store.object(forKey: key) as? String {
            syncedValue = value
        } else {
            syncedValue = ""
        }
    }

    func save(_ value: String) {
        store.set(value, forKey: key)
        store.synchronize()
        DispatchQueue.main.async {
            self.syncedValue = value
        }
    }
}

struct CloudKitKeyValueView: View {
    @StateObject private var viewModel = CloudKitKeyValueViewModel()
    @State private var editingValue: String = ""

    var body: some View {
        VStack(spacing: 16) {
            if !viewModel.isICloudAvailable, let message = viewModel.errorMessage {
                Text(message)
                    .font(.caption)
                    .foregroundStyle(.secondary)
                    .multilineTextAlignment(.center)
            }

            TextField("Synced value", text: $editingValue)
                .textFieldStyle(.roundedBorder)
                .disabled(!viewModel.isICloudAvailable)
                .onSubmit { viewModel.save(editingValue) }

            if viewModel.isICloudAvailable {
                Text("Synced: \(viewModel.syncedValue)")
                    .font(.caption)
            }
        }
        .onAppear { viewModel.checkAccountStatus() }
        .onChange(of: viewModel.syncedValue) { _, newValue in
            editingValue = newValue
        }
    }
}
